package genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.mapper.VehicleCategoryMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.repository.VehicleCategoryRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleCategoryService { private final VehicleCategoryRepository repository; private final VehicleCategoryMapper mapper; public VehicleCategoryService(VehicleCategoryRepository repository,VehicleCategoryMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleCategoryResponse> list(){ return repository.findAll().stream().map(mapper::toResponse).toList(); } public List<VehicleCategoryOptionResponse> options(String q, boolean activeOnly, int limit){ int safeLimit=Math.max(1, Math.min(limit, 200)); return repository.findOptions(q, activeOnly, safeLimit).stream().map(c -> new VehicleCategoryOptionResponse(c.categoryId(), c.categoryName())).toList(); } public VehicleCategoryResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleCategory", id.toString())); } public VehicleCategoryResponse create(VehicleCategoryUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleCategoryResponse update(UUID id,VehicleCategoryUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleCategory", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleCategory", id.toString()); } }
